        {
            return new ApiErrorResult(StatusCodes.Status400BadRequest, result);
        }
        return new ApiSuccessResult(StatusCodes.Status200OK, DepartmentResource.msgUnassignSuccess + $" ({defaultDepartment.DepartName})");
