        _configuration = configuration;
        _httpContext = httpContextAccessor.HttpContext;
        _mapper = mapper;
    }

    /// <summary>
    /// Get the setting
    /// </summary>
    /// <response code="401">Unauthorized: Lack of String Token Bearer</response>
