                    }
                }
                if (model.ApprovalStepNumber != (short)VisitSettingType.SecondStep)
                {
                    // update status of all user to Approval
                    _userService.UpdateAllUserCompanyToApproval(_httpContext.User.GetCompanyId(), model.ApprovalStepNumber);
                }
            }
            catch (Exception e)
